     1→import { useSprintTimer } from '@/hooks/useSprintTimer';
     2→import { cn } from '@/lib/utils';
     3→
     4→function formatTime(seconds: number): string {
     5→  const hours = Math.floor(seconds / 3600);
     6→  const minutes = Math.floor((seconds % 3600) / 60);
     7→  const secs = seconds % 60;
     8→  
     9→  return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    10→}
    11→
    12→function getTimerColor(remainingSeconds: number, status: string): string {
    13→  if (status === 'stopped') return 'text-muted-foreground';
    14→  if (status === 'paused') return 'text-yellow-600';
    15→  
    16→  if (remainingSeconds <= 60) return 'text-red-600 animate-pulse';
    17→  if (remainingSeconds <= 600) return 'text-red-600'; // < 10 min
    18→  if (remainingSeconds <= 1800) return 'text-yellow-600'; // < 30 min
    19→  return 'text-green-600';
    20→}
    21→
    22→function getStatusBadge(status: string): { label: string; className: string } {
    23→  switch (status) {
    24→    case 'running':
    25→      return { label: 'LIVE', className: 'bg-green-600 text-white' };
    26→    case 'paused':
    27→      return { label: 'PAUSED', className: 'bg-yellow-600 text-white' };
    28→    default:
    29→      return { label: 'READY', className: 'bg-muted text-muted-foreground' };
    30→  }
    31→}
    32→
    33→export function SprintTimer() {
    34→  const { remainingSeconds, status, loading } = useSprintTimer();
    35→  
    36→  if (loading) {
    37→    return (
    38→      <div className="border-4 border-foreground p-4 flex items-center justify-center gap-4">
    39→        <div className="w-6 h-6 border-4 border-foreground border-t-transparent rounded-full animate-spin" />
    40→        <span className="font-mono text-sm">Loading timer...</span>
    41→      </div>
    42→    );
    43→  }
    44→
    45→  const badge = getStatusBadge(status);
    46→  const timerColor = getTimerColor(remainingSeconds, status);
    47→
    48→  return (
    49→    <div className="border-4 border-foreground p-4 flex flex-col sm:flex-row items-center justify-between gap-4">
    50→      <div className="flex items-center gap-3">
    51→        <span className={cn('px-2 py-1 text-xs font-mono font-bold', badge.className)}>
    52→          {badge.label}
    53→        </span>
    54→        <span className="font-mono text-sm text-muted-foreground">SPRINT TIMER</span>
    55→      </div>
    56→      
    57→      <div className={cn('font-mono text-4xl sm:text-5xl font-bold tracking-wider', timerColor)}>
    58→        {formatTime(remainingSeconds)}
    59→      </div>
    60→      
    61→      {status === 'running' && remainingSeconds <= 1800 && (
    62→        <span className="font-mono text-xs text-muted-foreground animate-pulse">
    63→          {remainingSeconds <= 60 ? '⚡ FINAL MINUTE!' : remainingSeconds <= 600 ? '🔥 LESS THAN 10 MIN!' : '⏰ LESS THAN 30 MIN!'}
    64→        </span>
    65→      )}
    66→    </div>
    67→  );
    68→}
