    41→export default function AdminDisplay() {
    42→  const { remainingSeconds, status, displayPhase, promoCode, appLink, displayImageUrl, loading } = useSprintTimer();
    43→  const [cursorVisible, setCursorVisible] = useState(true);
    44→
    45→  const toggleFullscreen = useCallback(() => {
    46→    if (!document.fullscreenElement) {
    47→      document.documentElement.requestFullscreen();
    48→    } else {
    49→      document.exitFullscreen();
    50→    }
    51→  }, []);
    52→
    53→  // Handle keyboard shortcuts
    54→  useEffect(() => {
    55→    const handleKeyDown = (e: KeyboardEvent) => {
    56→      if (e.key === 'f' || e.key === 'F') {
    57→        toggleFullscreen();
    58→      }
    59→    };
    60→    window.addEventListener('keydown', handleKeyDown);
    61→    return () => window.removeEventListener('keydown', handleKeyDown);
    62→  }, [toggleFullscreen]);
    63→
    64→  // Auto-hide cursor after inactivity
    65→  useEffect(() => {
    66→    let timeout: NodeJS.Timeout;
    67→    const handleMouseMove = () => {
    68→      setCursorVisible(true);
    69→      clearTimeout(timeout);
    70→      timeout = setTimeout(() => setCursorVisible(false), 3000);
    71→    };
    72→    window.addEventListener('mousemove', handleMouseMove);
    73→    handleMouseMove(); // Start the timer
    74→    return () => {
    75→      window.removeEventListener('mousemove', handleMouseMove);
    76→      clearTimeout(timeout);
    77→    };
    78→  }, []);
    79→
    80→  if (loading) {
    81→    return (
    82→      <div className="min-h-screen bg-background flex items-center justify-center">
    83→        <div className="w-12 h-12 border-4 border-foreground border-t-transparent rounded-full animate-spin" />
    84→      </div>
    85→    );
    86→  }
    87→
    88→  const currentPhaseInfo = phases.find(p => p.key === displayPhase) || phases[0];
    89→  const currentIndex = phaseOrder.indexOf(displayPhase);
    90→  const timerColor = getTimerColor(remainingSeconds, status);
    91→
    92→  return (
    93→    <div 
    94→      className={cn(
    95→        "min-h-screen bg-background flex flex-col items-center justify-center p-4 gap-4",
    96→        !cursorVisible && "cursor-none"
    97→      )}
    98→    >
    99→      {/* Title */}
   100→      <h1 className="font-mono text-2xl md:text-3xl font-bold tracking-tight text-foreground">
   101→        [HABITAT] SPRINT
   102→      </h1>
   103→
   104→      {/* Timer Section */}
   105→      <div className="flex flex-col items-center gap-2">
   106→        <div className={cn('font-mono text-6xl md:text-7xl lg:text-8xl font-bold tracking-wider', timerColor)}>
   107→          {formatTime(remainingSeconds)}
   108→        </div>
   109→        <div className={cn(
   110→          'px-3 py-1 text-lg md:text-xl font-mono font-bold',
   111→          status === 'running' && 'bg-green-600 text-white',
   112→          status === 'paused' && 'bg-yellow-600 text-white',
   113→          status === 'stopped' && 'bg-muted text-muted-foreground'
   114→        )}>
   115→          {getStatusLabel(status)}
   116→        </div>
   117→      </div>
   118→
   119→      {/* Phase Name */}
   120→      <div className="text-center">
   121→        <p className="font-mono text-xl md:text-2xl font-bold text-foreground">
   122→          {displayPhase === 'completed' 
   123→            ? 'Sprint Complete! 🎉' 
   124→            : displayPhase === 'waiting'
   125→            ? 'Getting Started'
   126→            : `PHASE ${displayPhase.replace('phase_', '')} - ${currentPhaseInfo.name.toUpperCase()}`
   127→          }
   128→        </p>
   129→      </div>
   130→
   131→      {/* Phase Progress Dots */}
   132→      <div className="flex items-center justify-center gap-3 py-2">
   133→        {phases.slice(1, 5).map((phase, index) => {
   134→          const phaseIndex = phaseOrder.indexOf(phase.key);
   135→          const isCompleted = currentIndex > phaseIndex;
   136→          const isCurrent = displayPhase === phase.key;
   137→          
   138→          return (
   139→            <div key={phase.key} className="flex items-center">
   140→              <div
   141→                className={cn(
   142→                  'w-12 h-12 md:w-14 md:h-14 border-4 border-foreground flex items-center justify-center font-bold text-xl md:text-2xl transition-all',
   143→                  isCompleted && `phase-${index + 1} text-white`,
   144→                  isCurrent && `phase-${index + 1} text-white animate-pulse`,
   145→                  !isCompleted && !isCurrent && 'bg-muted text-muted-foreground'
   146→                )}
   147→              >
   148→                {isCompleted ? <Check className="w-6 h-6 md:w-8 md:h-8" /> : phase.label}
   149→              </div>
   150→              {index < 3 && (
   151→                <div
   152→                  className={cn(
   153→                    'w-8 md:w-12 h-1 border-y-2 border-foreground',
   154→                    currentIndex > phaseIndex + 1 ? 'bg-foreground' : 'bg-muted'
   155→                  )}
   156→                />
   157→              )}
   158→            </div>
   159→          );
   160→        })}
   161→      </div>
   162→
   163→      {/* App Link Section */}
   164→      {appLink && (
   165→        <div className="text-center mt-2">
   166→          <p className="font-mono text-sm md:text-base text-muted-foreground mb-1">📱 JOIN AT</p>
   167→          <p className="font-mono text-xl md:text-2xl lg:text-3xl font-bold text-foreground">
   168→            {appLink}
   169→          </p>
   170→        </div>
   171→      )}
   172→
   173→      {/* Promo Code & QR Image Section */}
   174→      {(promoCode || displayImageUrl) && (
   175→        <div className="flex flex-col md:flex-row items-center gap-4 mt-2">
   176→          {displayImageUrl && (
   177→            <div className="border-4 border-foreground p-2">
   178→              <img
   179→                src={displayImageUrl}
   180→                alt="WhatsApp QR Code"
   181→                className="max-h-32 md:max-h-40 object-contain"
   182→              />
   183→            </div>
   184→          )}
   185→          {promoCode && (
   186→            <div className="border-4 border-foreground p-4 md:p-6 text-center">
   187→              <p className="font-mono text-sm md:text-base text-muted-foreground mb-1">🎁 PROMO CODE</p>
   188→              <p className="font-mono text-2xl md:text-3xl lg:text-4xl font-bold text-foreground tracking-widest">
   189→                {promoCode}
   190→              </p>
   191→            </div>
   192→          )}
   193→        </div>
   194→      )}
   195→
   196→      {/* Fullscreen hint */}
   197→      <p className="fixed bottom-4 right-4 font-mono text-xs text-muted-foreground opacity-50">
   198→        Press F for fullscreen
   199→      </p>
   200→    </div>
   201→  );
   202→}
