    44→
    45→export function PhaseChecklist({
    46→  phase,
    47→  label,
    48→  description,
    49→  phaseNote,
    50→  tasks,
    51→  teamId,
    52→  currentPhase,
    53→  completedTasks,
    54→  taskContents,
    55→  phase1Data,
