import { useState } from 'react';
import { ChevronDown, ChevronUp, Clock, CheckCircle2, Circle, Settings, Users, Rocket, Zap } from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { getTrackPhases, type TrackType } from '@/data/trackConfig';
import type { TeamWithProgress } from '@/hooks/useAdminData';
import { formatDistanceToNow } from 'date-fns';
import { MarkdownRenderer } from '@/components/ui/markdown-renderer';
import { TeamManagementDialog } from './TeamManagementDialog';

interface TeamProgressCardProps {
  team: TeamWithProgress;
  onTeamUpdated: () => void;
}

const phaseLabels: Record<string, string> = {
  waiting: 'Waiting',
  phase_1: 'Phase 1',
  phase_2: 'Phase 2',
  phase_3: 'Phase 3',
  phase_4: 'Phase 4',
  completed: 'Completed',
};

const phaseBadgeColors: Record<string, string> = {
  waiting: 'bg-muted text-muted-foreground',
  phase_1: 'bg-blue-500 text-white',
  phase_2: 'bg-yellow-500 text-black',
  phase_3: 'bg-orange-500 text-white',
  phase_4: 'bg-purple-500 text-white',
  completed: 'bg-green-500 text-white',
};

export function TeamProgressCard({ team, onTeamUpdated }: TeamProgressCardProps) {
  const [isExpanded, setIsExpanded] = useState(false);
  const [showManageDialog, setShowManageDialog] = useState(false);

  const completedTaskKeys = new Set(
    team.taskProgress.filter((t) => t.completed).map((t) => t.task_key)
  );

  const taskContents = new Map(
    team.taskProgress.map((t) => [t.task_key, t.content])
  );

  const progressPercentage = (team.completedTasks / team.totalTasks) * 100;

  return (
    <Card className="border-4 border-foreground overflow-hidden">
      <CardContent className="p-0">
        {/* Header Row */}
        <div 
          className="flex items-center justify-between p-4 cursor-pointer hover:bg-muted/50 transition-colors"
          onClick={() => setIsExpanded(!isExpanded)}
        >
          <div className="flex items-center gap-4 flex-1 min-w-0">
            <div className="flex-1 min-w-0">
              <h3 className="font-mono font-bold text-lg truncate">{team.name}</h3>
              <div className="flex flex-wrap items-center gap-x-3 gap-y-1">
                {team.track && (
                  <Badge variant="outline" className="font-mono text-xs flex items-center gap-1">
                    {team.track === 'automation' ? <Zap className="w-3 h-3" /> : <Rocket className="w-3 h-3" />}
                    {team.track === 'automation' ? 'Automation' : 'Startup'}
                  </Badge>
                )}
                {team.memberNames.length > 0 && (
                  <p className="text-muted-foreground text-xs font-mono flex items-center gap-1">
                    <Users className="w-3 h-3" />
                    {team.memberNames.join(', ')}
                  </p>
                )}
                {team.lastActivity && (
                  <p className="text-muted-foreground text-xs font-mono flex items-center gap-1">
                    <Clock className="w-3 h-3" />
                    {formatDistanceToNow(new Date(team.lastActivity), { addSuffix: true })}
                  </p>
                )}
              </div>
            </div>

            <Badge className={`${phaseBadgeColors[team.currentPhase]} font-mono shrink-0`}>
              {phaseLabels[team.currentPhase]}
            </Badge>

            <div className="hidden sm:flex items-center gap-2 shrink-0">
              <div className="w-24 h-2 bg-muted border border-foreground overflow-hidden">
                <div 
                  className="h-full bg-foreground transition-all duration-300"
                  style={{ width: `${progressPercentage}%` }}
                />
              </div>
              <span className="font-mono text-sm w-16 text-right">
                {team.completedTasks}/{team.totalTasks}
              </span>
            </div>
          </div>

          <Button variant="ghost" size="icon" className="ml-2 shrink-0">
            {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
          </Button>
          <Button
            variant="outline"
            size="icon"
            className="ml-1 shrink-0 border-2 border-foreground"
            onClick={(e) => {
              e.stopPropagation();
              setShowManageDialog(true);
            }}
          >
            <Settings className="w-4 h-4" />
          </Button>
        </div>

        {/* Expanded Details */}
        {isExpanded && (
          <div className="border-t-4 border-foreground p-4 space-y-4 bg-muted/30">
            {getTrackPhases((team.track as TrackType) || 'startup').map((phase) => {
              const phaseCompleted = phase.tasks.filter((t) => completedTaskKeys.has(t.key)).length;
              const isCurrentPhase = team.currentPhase === phase.phase;

              return (
                <div 
                  key={phase.phase}
                  className={`border-2 border-foreground p-3 ${isCurrentPhase ? 'bg-background ring-2 ring-primary' : ''}`}
                >
                  <div className="flex items-center justify-between mb-2">
                    <h4 className="font-mono font-bold text-sm flex items-center gap-2">
                      {phase.label}
                      {isCurrentPhase && (
                        <Badge variant="outline" className="text-xs font-mono">
                          CURRENT
                        </Badge>
                      )}
                    </h4>
                    <span className="font-mono text-xs text-muted-foreground">
                      {phaseCompleted}/{phase.tasks.length}
                    </span>
                  </div>

                  <div className="space-y-2">
                    {phase.tasks.map((task) => {
                      const isCompleted = completedTaskKeys.has(task.key);
                      const content = taskContents.get(task.key);

                      return (
                        <div 
                          key={task.key}
                          className={`flex gap-2 ${isCompleted ? '' : 'opacity-50'}`}
                        >
                          {isCompleted ? (
                            <CheckCircle2 className="w-4 h-4 text-green-600 shrink-0 mt-0.5" />
                          ) : (
                            <Circle className="w-4 h-4 text-muted-foreground shrink-0 mt-0.5" />
                          )}
                          <div className="flex-1 min-w-0">
                            <p className="font-mono text-xs font-medium">{task.title}</p>
                            {isCompleted && content && (
                              <div className="text-xs text-muted-foreground mt-1 bg-muted p-2 border border-foreground/20 break-words max-h-32 overflow-y-auto">
                                <MarkdownRenderer content={content || ''} className="text-xs" />
                              </div>
                            )}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </CardContent>

      <TeamManagementDialog
        team={team}
        open={showManageDialog}
        onOpenChange={setShowManageDialog}
        onTeamUpdated={onTeamUpdated}
      />
    </Card>
  );
}

import { useState, useEffect, useMemo, useRef } from 'react';
import { ChevronDown, ChevronRight, Check, Info } from 'lucide-react';
import { cn } from '@/lib/utils';
import { TaskInputItem } from './TaskInputItem';
import { AIGeneratedTaskItem } from './AIGeneratedTaskItem';
import confetti from 'canvas-confetti';
import type { SprintTask } from '@/data/sprintTasks';
import type { Phase1Data } from '@/hooks/useAIGeneration';

interface PhaseChecklistProps {
  phase: string;
  label: string;
  description: string;
  phaseNote?: string;
  tasks: SprintTask[];
  teamId: string;
  currentPhase: string;
  completedTasks: Set<string>;
  taskContents: Map<string, string | null>;
  phase1Data: Phase1Data;
  phase1Complete: boolean;
  missingPhase1Tasks: string[];
  onTaskSave: (taskKey: string, content: string, phase: string) => Promise<void>;
}

const phaseColorClasses: Record<string, string> = {
  phase_1: 'phase-1',
  phase_2: 'phase-2',
  phase_3: 'phase-3',
  phase_4: 'phase-4',
};

const phaseOrder = ['waiting', 'phase_1', 'phase_2', 'phase_3', 'phase_4', 'completed'];

const taskTitleMap: Record<string, string> = {
  p1_problem: 'Problem Statement',
  p1_solution: 'Solution',
  p1_customer: 'Target Customer',
  a1_workflow: 'Workflow Description',
  a1_pain_points: 'Pain Points',
  a1_tools: 'Tools Involved',
  a1_time_spent: 'Time Spent',
};

export function PhaseChecklist({
  phase,
  label,
  description,
  phaseNote,
  tasks,
  teamId,
  currentPhase,
  completedTasks,
  taskContents,
  phase1Data,
  phase1Complete,
  missingPhase1Tasks,
  onTaskSave,
}: PhaseChecklistProps) {
  const [isOpen, setIsOpen] = useState(false);
  const prevCompletedCount = useRef(0);

  const currentIndex = phaseOrder.indexOf(currentPhase);
  const phaseIndex = phaseOrder.indexOf(phase);
  const isActive = currentPhase === phase;
  const isPast = currentIndex > phaseIndex;
  const isFuture = currentIndex < phaseIndex;

  // Auto-expand current phase
  useEffect(() => {
    if (isActive) {
      setIsOpen(true);
    }
  }, [isActive]);

  const completedCount = tasks.filter((t) => completedTasks.has(t.key)).length;
  const allCompleted = completedCount === tasks.length;

  // Trigger confetti when phase is completed
  useEffect(() => {
    if (allCompleted && prevCompletedCount.current < tasks.length && prevCompletedCount.current > 0) {
      // Big celebration for phase completion
      confetti({
        particleCount: 100,
        spread: 70,
        origin: { y: 0.6 },
        colors: ['#10b981', '#34d399', '#6ee7b7', '#fbbf24', '#f59e0b'],
      });

      // Second burst
      setTimeout(() => {
        confetti({
          particleCount: 50,
          angle: 60,
          spread: 55,
          origin: { x: 0 },
          colors: ['#10b981', '#34d399', '#6ee7b7'],
        });
      }, 200);

      setTimeout(() => {
        confetti({
          particleCount: 50,
          angle: 120,
          spread: 55,
          origin: { x: 1 },
          colors: ['#10b981', '#34d399', '#6ee7b7'],
        });
      }, 400);
    }
    prevCompletedCount.current = completedCount;
  }, [allCompleted, completedCount, tasks.length]);

  const handleSave = async (taskKey: string, content: string) => {
    await onTaskSave(taskKey, content, phase);
  };

  // Get human-readable missing task names
  const missingTaskNames = useMemo(() => {
    return missingPhase1Tasks.map(key => taskTitleMap[key] || key);
  }, [missingPhase1Tasks]);

  // Build phase1Data with mvpScope if available
  const enrichedPhase1Data = useMemo(() => {
    const mvpScope = taskContents.get('p2_scope') || undefined;
    return { ...phase1Data, mvpScope };
  }, [phase1Data, taskContents]);

  return (
    <div
      className={cn(
        'border-4 border-foreground overflow-hidden',
        isFuture && 'opacity-50'
      )}
    >
      <div
        className={cn(
          'flex items-center justify-between p-4 transition-colors',
          isActive && phaseColorClasses[phase],
          isActive && 'text-white',
          isPast && allCompleted && 'bg-success text-success-foreground',
          isPast && !allCompleted && 'bg-secondary',
          isFuture && 'bg-muted'
        )}
      >
        <button
          onClick={() => setIsOpen(!isOpen)}
          className="flex items-center gap-4 text-left flex-1"
        >
          {isOpen ? (
            <ChevronDown className="w-6 h-6" />
          ) : (
            <ChevronRight className="w-6 h-6" />
          )}
          <div>
            <h3 className="font-bold text-xl">{label}</h3>
            <p className="font-mono text-sm opacity-80">{description}</p>
          </div>
        </button>
        <div className="flex items-center gap-3">
          <span className="font-mono text-sm">
            {completedCount}/{tasks.length}
          </span>
          {allCompleted && <Check className="w-6 h-6" />}
        </div>
      </div>

      {isOpen && (
        <div className="p-4 space-y-3 bg-card">
          {/* Phase note at the top */}
          {phaseNote && (
            <div className="flex items-start gap-2 p-3 bg-muted/50 border-2 border-foreground/20 rounded mb-4">
              <Info className="w-4 h-4 mt-0.5 text-muted-foreground flex-shrink-0" />
              <p className="font-mono text-sm text-muted-foreground">
                {phaseNote}
              </p>
            </div>
          )}

          {tasks.map((task) => {
            if (task.inputType === 'ai-generated' && task.aiConfig) {
              return (
                <AIGeneratedTaskItem
                  key={task.key}
                  id={task.key}
                  title={task.title}
                  description={task.description}
                  aiConfig={task.aiConfig}
                  checked={completedTasks.has(task.key)}
                  content={taskContents.get(task.key) || undefined}
                  phase1Data={enrichedPhase1Data}
                  phase1Complete={phase1Complete}
                  missingTasks={missingTaskNames}
                  onSave={handleSave}
                  disabled={isFuture}
                />
              );
            }

            return (
              <TaskInputItem
                key={task.key}
                id={task.key}
                title={task.title}
                description={task.description}
                exampleText={task.exampleText}
                warningText={task.warningText}
                helperText={task.helperText}
                toolLink={task.toolLink}
                inputType={task.inputType}
                placeholder={task.placeholder}
                checked={completedTasks.has(task.key)}
                content={taskContents.get(task.key) || undefined}
                optional={task.optional}
                recommended={task.recommended}
                subNote={task.subNote}
                checklist={task.checklist}
                onSave={handleSave}
                disabled={isFuture}
              />
            );
          })}
        </div>
      )}
    </div>
  );
}

