      searchFilters?: SearchFilters;
      track?: TrackType;
    };

    // Rate limit by authorization token
    const authToken = req.headers.get("authorization") || "anonymous";
    const rateCheck = checkRateLimit(authToken);
    if (!rateCheck.allowed) {
      return new Response(
        JSON.stringify({
          error: `You've used all ${RATE_LIMIT_MAX} AI generations this hour. Try again in ${Math.ceil((rateCheck.retryAfterSec || 60) / 60)} minutes.`,
